import java.io.*; import java.util.*; import java.util.zip.*; import java.nio.file.*; public class ApkPatcher { public static void main(String[] args) throws Exception { File apkFile = new File("final_notes.apk"); File tempFile = new File("final_notes_temp.apk"); ZipInputStream zin = new ZipInputStream(new FileInputStream(apkFile)); ZipOutputStream zout = new ZipOutputStream(new FileOutputStream(tempFile)); Set<String> replaced = new HashSet<>(); replaced.add("classes.dex"); replaced.add("classes2.dex"); replaced.add("lib/arm64-v8a/libapp.so"); replaced.add("lib/arm64-v8a/libclib.so"); replaced.add("lib/arm64-v8a/libflutter.so"); replaced.add("lib/arm64-v8a/libobjectbox-jni.so"); replaced.add("lib/arm64-v8a/libpbkdf2_native.so"); replaced.add("lib/arm64-v8a/libpolarssl.so"); replaced.add("lib/arm64-v8a/libsecurity.so"); replaced.add("lib/arm64-v8a/libtmlib.so"); ZipEntry entry = zin.getNextEntry(); while (entry != null) { String name = entry.getName(); if (!replaced.contains(name)) { zout.putNextEntry(new ZipEntry(name)); byte[] buf = new byte[1024]; int len; while ((len = zin.read(buf)) > 0) { zout.write(buf, 0, len); } zout.closeEntry(); } entry = zin.getNextEntry(); } zin.close(); addFile(zout, "prebuilt/dex/classes.dex", "classes.dex"); addFile(zout, "prebuilt/dex/classes2.dex", "classes2.dex"); String libBase = "prebuilt/lib/arm64-v8a/"; String[] libs = {"libapp.so", "libclib.so", "libflutter.so", "libobjectbox-jni.so", "libpbkdf2_native.so", "libpolarssl.so", "libsecurity.so", "libtmlib.so"}; for (String lib : libs) { addFile(zout, libBase + lib, "lib/arm64-v8a/" + lib); } zout.close(); apkFile.delete(); tempFile.renameTo(apkFile); } private static void addFile(ZipOutputStream zout, String srcPath, String entryName) throws IOException { zout.putNextEntry(new ZipEntry(entryName)); byte[] buf = Files.readAllBytes(Paths.get(srcPath)); zout.write(buf, 0, buf.length); zout.closeEntry(); } }
